"""
OmegA CLI Git — Git integration for status, diffs, and commits.
"""

import subprocess
from pathlib import Path
from typing import Optional, List, Tuple, Dict, Any


def run_git_command(cmd: List[str]) -> Tuple[bool, str]:
    """Run a git command and return success status and output."""
    try:
        result = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            timeout=10,
        )
        return result.returncode == 0, result.stdout.strip()
    except subprocess.TimeoutExpired:
        return False, "Git command timed out"
    except Exception as e:
        return False, str(e)


def git_status() -> str:
    """Get git status."""
    success, output = run_git_command(["git", "status", "-s"])
    if not success:
        return "Not a git repository"
    return output or "Clean working directory"


def git_branch() -> str:
    """Get current git branch."""
    success, output = run_git_command(
        ["git", "rev-parse", "--abbrev-ref", "HEAD"]
    )
    return output if success else "unknown"


def git_log(limit: int = 10) -> str:
    """Get recent git commits."""
    success, output = run_git_command(
        ["git", "log", f"-{limit}", "--oneline", "--decorate"]
    )
    return output if success else "No git history"


def git_diff(file_path: Optional[str] = None) -> str:
    """Get git diff, optionally for a specific file."""
    cmd = ["git", "diff"]
    if file_path:
        cmd.append(file_path)

    success, output = run_git_command(cmd)
    return output if success else "No changes"


def git_staged_diff() -> str:
    """Get diff of staged changes."""
    success, output = run_git_command(["git", "diff", "--cached"])
    return output if success else "No staged changes"


def git_add(file_path: str) -> Tuple[bool, str]:
    """Stage a file for commit."""
    success, output = run_git_command(["git", "add", file_path])
    return success, output if output else "File staged"


def git_commit(message: str) -> Tuple[bool, str]:
    """Commit staged changes."""
    success, output = run_git_command(["git", "commit", "-m", message])
    return success, output


def git_push(branch: Optional[str] = None) -> Tuple[bool, str]:
    """Push commits to remote."""
    cmd = ["git", "push"]
    if branch:
        cmd.extend(["-u", "origin", branch])

    success, output = run_git_command(cmd)
    return success, output


def git_create_pr(title: str, description: str = "") -> Tuple[bool, str]:
    """Create a pull request using gh CLI."""
    try:
        cmd = ["gh", "pr", "create", "--title", title]
        if description:
            cmd.extend(["--body", description])

        success, output = run_git_command(cmd)
        return success, output
    except Exception as e:
        return False, str(e)


def git_info() -> Dict[str, Any]:
    """Get comprehensive git info."""
    return {
        "branch": git_branch(),
        "status": git_status(),
        "log": git_log(5),
    }


def git_is_repo() -> bool:
    """Check if current directory is a git repository."""
    success, _ = run_git_command(["git", "rev-parse", "--git-dir"])
    return success

