"""
OmegA CLI Version — Version management and updates.
"""

from pathlib import Path
from typing import Optional, Tuple


class VersionManager:
    """Manages CLI versioning."""

    def __init__(self, version_file: Optional[Path] = None):
        """Initialize version manager."""
        if version_file is None:
            version_file = Path(__file__).parent.parent / "VERSION"

        self.version_file = version_file

    def get_version(self) -> str:
        """Get current version."""
        if self.version_file.exists():
            return self.version_file.read_text().strip()
        return "unknown"

    def set_version(self, version: str) -> None:
        """Set version."""
        self.version_file.write_text(f"{version}\n")

    def parse_version(self, version_str: str) -> Tuple[int, int, int]:
        """Parse semantic version string."""
        parts = version_str.split(".")
        try:
            return int(parts[0]), int(parts[1]) if len(parts) > 1 else 0, int(parts[2]) if len(parts) > 2 else 0
        except (ValueError, IndexError):
            return 0, 0, 0

    def is_newer_version(self, current: str, candidate: str) -> bool:
        """Check if candidate version is newer than current."""
        curr = self.parse_version(current)
        cand = self.parse_version(candidate)
        return cand > curr

    def get_changelog(self) -> str:
        """Get changelog content."""
        changelog_file = Path(__file__).parent.parent / "CHANGELOG.md"

        if changelog_file.exists():
            return changelog_file.read_text()

        return "No changelog available"


# Global instance
_version_manager: Optional[VersionManager] = None


def get_version_manager() -> VersionManager:
    """Get the global version manager instance."""
    global _version_manager
    if _version_manager is None:
        _version_manager = VersionManager()
    return _version_manager

